import { HelpCircle } from 'lucide-react'
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion'
import useKnowledgeStore from '@/stores/useKnowledgeStore'

export default function FAQ() {
  const { faqs } = useKnowledgeStore()

  return (
    <div className="container max-w-4xl mx-auto px-4 py-8 md:py-12 animate-fade-in-up">
      <div className="space-y-4 mb-10 text-center">
        <div className="flex justify-center mb-4">
          <div className="bg-primary/10 p-4 rounded-full">
            <HelpCircle className="w-8 h-8 text-primary" />
          </div>
        </div>
        <h1 className="text-3xl md:text-5xl font-bold tracking-tight text-foreground">
          Perguntas Frequentes (FAQ)
        </h1>
        <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
          Tire suas dúvidas sobre impressão, materiais, montagem e acesso aos seus arquivos.
        </p>
      </div>

      <div className="bg-card rounded-xl border shadow-sm p-6 md:p-8">
        <Accordion type="single" collapsible className="w-full">
          {faqs.map((faq, index) => (
            <AccordionItem key={faq.id} value={`item-${index}`}>
              <AccordionTrigger>{faq.question}</AccordionTrigger>
              <AccordionContent>
                <div dangerouslySetInnerHTML={{ __html: faq.answer }} />
              </AccordionContent>
            </AccordionItem>
          ))}

          {faqs.length === 0 && (
            <div className="text-center py-8 text-muted-foreground">
              Nenhuma pergunta frequente cadastrada no momento.
            </div>
          )}
        </Accordion>
      </div>
    </div>
  )
}
